args.sqlite_command:
UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 900 AND 999;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE CITY1 IN ('Wiblingwerde', 'Breckerfeld');

UPDATE J09A_final
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (
  SELECT EQUNR FROM J09A_mr_agg
  WHERE cnt_ms_2024 > 0 AND cnt_ms_2023 > 0
);

